mapper.select:
SELECT COUNT(*)
FROM admin_action_log l
INNER JOIN members m ON m.member_id = l.admin_id


        AND l.action_type = #{actionType}


        AND (m.email LIKE CONCAT('%', #{admin}, '%')
            OR m.name LIKE CONCAT('%', #{admin}, '%'))


        AND DATE(l.created_at) >= #{from}


        AND DATE(l.created_at) <= #{to}

SELECT l.admin_action_log_id AS adminActionLogId, l.admin_id AS adminId, m.email AS adminEmail, m.name AS adminName, l.action_type AS actionType, l.target_type AS targetType, l.target_id AS targetId, l.action_detail AS actionDetail, l.created_at AS createdAt FROM admin_action_log l INNER JOIN members m ON m.member_id = l.admin_id
AND l.action_type = #{actionType}
AND (m.email LIKE CONCAT('%', #{admin}, '%') OR m.name LIKE CONCAT('%', #{admin}, '%'))
AND DATE(l.created_at) >= #{from}
AND DATE(l.created_at) <= #{to}
ORDER BY l.created_at DESC, l.admin_action_log_id DESC LIMIT #{limit} OFFSET #{offset}
